agents.prompt:
{
  "nodes": [
    {
      "type": "n8n-nodes-base.notion",
      "name": "Fetch 1on1 Notes",
      "parameters": {
        "operation": "getAll",
        "databaseId": "[NOTION_1ON1_DB_ID]",
        "filterByFormula": "AND(IS_AFTER({Date}, DATEADD(TODAY(), -7, 'days')), {Type} = '1-on-1')"
      }
    },
    {
      "type": "n8n-nodes-base.notion",
      "name": "Fetch Completed Tasks",
      "parameters": {
        "operation": "getAll",
        "databaseId": "[NOTION_TASKS_DB_ID]",
        "filterByFormula": "AND(IS_AFTER({CompletedAt}, DATEADD(TODAY(), -7, 'days')), {Status} = 'Done')"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Analyze Growth Signals",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Данные за неделю по команде: 1-on-1 заметки: {{$node['Fetch 1on1 Notes'].json}}. Завершённые задачи: {{$node['Fetch Completed Tasks'].json}}. Выдели по каждому сотруднику: 1 сигнал роста, 1 область для развития. Формат: таблица имя | сигнал роста | область развития."
      }
    },
    {
      "type": "n8n-nodes-base.notion",
      "name": "Save to Dashboard",
      "parameters": {
        "operation": "create",
        "databaseId": "[NOTION_DASHBOARD_DB_ID]"
      }
    }
  ]
}

{
  "nodes": [
    {
      "type": "n8n-nodes-base.notion",
      "name": "Fetch Routine Tracker",
      "parameters": {
        "operation": "getAll",
        "databaseId": "[NOTION_ROUTINES_DB_ID]",
        "filterByFormula": "{Type} = 'Routine'"
      }
    },
    {
      "type": "n8n-nodes-base.code",
      "name": "Check Completion",
      "parameters": {
        "code": "const routines = items[0].json; const today = new Date(); const overdue = routines.filter(r => { const lastDone = new Date(r.lastCompleted); const freq = r.frequencyDays; return (today - lastDone) / 86400000 > freq * 1.2; }); return overdue.map(r => ({json: r}));"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Generate Alert Message",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Просроченные рутины: {{$json}}. Напиши краткое напоминание (2 предложения) для каждой: что пропущено и какой риск создаёт пропуск."
      }
    },
    {
      "type": "n8n-nodes-base.telegram",
      "name": "Send Alert",
      "parameters": {
        "chatId": "[TELEGRAM_CHAT_ID]",
        "text": "{{$json.message}}"
      }
    }
  ]
}

{
  "nodes": [
    {
      "type": "n8n-nodes-base.notion",
      "name": "Fetch Active Goals",
      "parameters": {
        "operation": "getAll",
        "databaseId": "[NOTION_GOALS_DB_ID]",
        "filterByFormula": "{Status} = 'Active'"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Define Weekly Focus",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Активные цели: {{$json}}. Определи 3 и только 3 приоритета на эту неделю. Для каждого: конкретное действие, ожидаемый результат к пятнице, необходимые ресурсы. Формат: нумерованный список приоритетов."
      }
    },
    {
      "type": "n8n-nodes-base.googleCalendar",
      "name": "Block Focus Time",
      "parameters": {
        "operation": "create",
        "calendarId": "[CALENDAR_ID]",
        "title": "FOCUS: {{$json.priority}}",
        "start": "[MONDAY_9AM]",
        "end": "[MONDAY_11AM]"
      }
    },
    {
      "type": "n8n-nodes-base.notion",
      "name": "Save Weekly Plan",
      "parameters": {
        "operation": "create",
        "databaseId": "[NOTION_WEEKLY_DB_ID]"
      }
    }
  ]
}

{
  "nodes": [
    {
      "type": "n8n-nodes-base.notion",
      "name": "Fetch Recent Comments",
      "parameters": {
        "operation": "getAll",
        "databaseId": "[NOTION_DISCUSSIONS_DB_ID]",
        "filterByFormula": "IS_AFTER({CreatedAt}, DATEADD(TODAY(), -3, 'days'))"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Analyze Tone",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Комментарии и обсуждения за 3 дня: {{$json}}. Оцени тональность по каждому треду: нейтральная / напряжённая / конфликтная. Для напряжённых и конфликтных — выдели конкретные сигналы и стороны. Верни JSON: [{thread, tone, signals, parties}]"
      }
    },
    {
      "type": "n8n-nodes-base.code",
      "name": "Filter Alerts",
      "parameters": {
        "code": "return items.filter(i => i.json.tone !== 'neutral');"
      }
    },
    {
      "type": "n8n-nodes-base.telegram",
      "name": "Send Warning",
      "parameters": {
        "chatId": "[TELEGRAM_CHAT_ID]",
        "text": "Сигнал напряжения в обсуждении: {{$json.thread}}. Тон: {{$json.tone}}. Стороны: {{$json.parties}}."
      }
    }
  ]
}

{
  "nodes": [
    {
      "type": "n8n-nodes-base.webhook",
      "name": "Receive Idea",
      "parameters": {
        "httpMethod": "POST",
        "path": "idea-capture"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Process Idea",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Сырая заметка: {{$json.text}}. 1) Сформулируй идею в одном предложении. 2) Присвой теги из списка: [продукт, процесс, команда, клиент, технология, стратегия]. 3) Оцени потенциал: высокий / средний / низкий. 4) Найди 1-2 идеи из базы {{$json.existingIdeas}}, с которыми есть связь. Верни JSON: {title, tags, potential, relatedIdeas}"
      }
    },
    {
      "type": "n8n-nodes-base.notion",
      "name": "Save to Ideas DB",
      "parameters": {
        "operation": "create",
        "databaseId": "[NOTION_IDEAS_DB_ID]",
        "properties": {
          "Title": "{{$json.title}}",
          "Tags": "{{$json.tags}}",
          "Potential": "{{$json.potential}}",
          "Raw": "{{$node['Receive Idea'].json.text}}"
        }
      }
    }
  ]
}

{
  "nodes": [
    {
      "type": "n8n-nodes-base.telegram",
      "name": "Send Pulse Survey",
      "parameters": {
        "chatId": "[GROUP_CHAT_ID]",
        "text": "Пульс-опрос (анонимно, 2 вопроса):\n1. По шкале 1-5: насколько твой голос слышен в команде?\n2. Есть что-то важное, что не было сказано на этой неделе? (необязательно)\nОтветь в личку боту: [BOT_LINK]"
      }
    },
    {
      "type": "n8n-nodes-base.code",
      "name": "Aggregate Responses",
      "parameters": {
        "code": "const responses = items.map(i => i.json); const avg = responses.reduce((s, r) => s + r.score, 0) / responses.length; const comments = responses.filter(r => r.comment).map(r => r.comment); return [{json: {avgScore: avg, comments, totalResponses: responses.length}}];"
      }
    },
    {
      "type": "n8n-nodes-base.claude",
      "name": "Analyze Inclusion Health",
      "parameters": {
        "model": "claude-sonnet-4-5",
        "prompt": "Результаты пульса: средний балл {{$json.avgScore}}, комментарии: {{$json.comments}}. Оцени: 1) Общее состояние вовлечённости. 2) Тревожные сигналы если есть. 3) Одно конкретное действие на следующей неделе для улучшения."
      }
    },
    {
      "type": "n8n-nodes-base.notion",
      "name": "Save Results",
      "parameters": {
        "operation": "create",
        "databaseId": "[NOTION_PULSE_DB_ID]"
      }
    }
  ]
}
